powershell -File - << 'EOF'
$dst = 'C:\Temp\_1c_copy.xgwx'
$bytes = [System.IO.File]::ReadAllBytes($dst)
# Check for ZIP signature (PK = 50 4B)
Write-Host "Bytes 0-3: $($bytes[0].ToString('X2')) $($bytes[1].ToString('X2')) $($bytes[2].ToString('X2')) $($bytes[3].ToString('X2'))"
Write-Host "Total size: $($bytes.Length)"

# Scan for ZIP PK header anywhere in file
for ($i = 0; $i -lt [Math]::Min($bytes.Length - 1, 1000); $i++) {
    if ($bytes[$i] -eq 0x50 -and $bytes[$i+1] -eq 0x4B) {
        Write-Host "ZIP PK signature found at offset: $i"
        break
    }
}

# Check for common XML strings anywhere
$xmlBytes = [System.Text.Encoding]::Unicode.GetBytes('<')
Write-Host "Searching for Unicode XML..."
for ($i = 0; $i -lt [Math]::Min($bytes.Length - 100, 2000); $i++) {
    if ($bytes[$i] -eq 0x3C -and $bytes[$i+1] -eq 0x00) {
        $sample = [System.Text.Encoding]::Unicode.GetString($bytes[$i..([Math]::Min($i+80, $bytes.Length-1))])
        Write-Host "Unicode XML at offset $i`: $sample"
        break
    }
}
EOF

powershell -File - << 'EOF'
$dst = 'C:\Temp\_1c_copy.xgwx'
$bytes = [System.IO.File]::ReadAllBytes($dst)

# XG 워크스페이스 파일 헤더 분석 - 오프셋별 확인
Write-Host "=== Header bytes 0-63 ==="
for ($i = 0; $i -lt 64; $i += 8) {
    $hex = ($bytes[$i..($i+7)] | ForEach-Object { $_.ToString('X2') }) -join ' '
    $ascii = ($bytes[$i..($i+7)] | ForEach-Object { if ($_ -ge 0x20 -and $_ -le 0x7E) { [char]$_ } else { '.' } }) -join ''
    Write-Host "  [$i] $hex  $ascii"
}

# zlib 압축 시그니처 확인 (78 9C, 78 DA, 78 01)
Write-Host "`n=== Searching for zlib/deflate headers ==="
for ($i = 0; $i -lt $bytes.Length - 1; $i++) {
    if (($bytes[$i] -eq 0x78) -and ($bytes[$i+1] -in @(0x9C, 0xDA, 0x01, 0x5E))) {
        Write-Host "zlib header at offset $i`: $($bytes[$i].ToString('X2')) $($bytes[$i+1].ToString('X2'))"
    }
}
EOF

powershell -File - << 'EOF'
$dst = 'C:\Temp\_1c_copy.xgwx'
$stream = [System.IO.File]::Open($dst, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
$reader = New-Object System.IO.BinaryReader($stream)
$bytes = $reader.ReadBytes(15204)
$reader.Close()
$stream.Close()

# 접근 방식 변경: 파일 전체에서 알려진 변수 패턴 검색
# UTF-16LE로 "_00_IN", "_01_IN", "P0000" 등 검색
$patterns = @('_IN0', '_OUT', 'P000', 'IN00', 'OUT0', 'Comment', 'Symbol')
foreach ($pat in $patterns) {
    $patBytes = [System.Text.Encoding]::Unicode.GetBytes($pat)
    $found = $false
    for ($i = 0; $i -lt ($bytes.Length - $patBytes.Length); $i++) {
        $match = $true
        for ($j = 0; $j -lt $patBytes.Length; $j++) {
            if ($bytes[$i+$j] -ne $patBytes[$j]) { $match = $false; break }
        }
        if ($match) {
            # 앞뒤 컨텍스트 읽기
            $start = [Math]::Max(0, $i - 20)
            $end = [Math]::Min($bytes.Length-1, $i + 80)
            $ctx = [System.Text.Encoding]::Unicode.GetString($bytes[$start..$end])
            Write-Host "Found '$pat' at offset $i`: $ctx"
            Write-Host "---"
            $found = $true
            break
        }
    }
    if (!$found) { Write-Host "Pattern '$pat' NOT found in file" }
}
EOF

