powershell -File - << 'EOF'
$dst = 'C:\Temp\_1c_copy.xgwx'
$stream = [System.IO.File]::Open($dst, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
$reader = New-Object System.IO.BinaryReader($stream)
$allBytes = $reader.ReadBytes(15204)
$reader.Close()
$stream.Close()

# gzip 시그니처 1F 8B 찾기
$gzOffset = -1
for ($i = 0; $i -lt 300; $i++) {
    if ($allBytes[$i] -eq 0x1F -and $allBytes[$i+1] -eq 0x8B) {
        $gzOffset = $i
        Write-Host "gzip at offset $i"
        break
    }
}

if ($gzOffset -ge 0) {
    $gzLen = $allBytes.Length - $gzOffset - 226  # tail 제거
    $gzBytes = $allBytes[$gzOffset..($gzOffset + $gzLen - 1)]
    [System.IO.File]::WriteAllBytes('C:\Temp\data.gz', $gzBytes)
    Write-Host "Saved: $($gzBytes.Length) bytes"
} else {
    Write-Host "gzip not found"
}
EOF

powershell -File - << 'EOF'
# data.gz 파일이 저장됐는지 확인 후 압축 해제
$gzPath = 'C:\Temp\data.gz'
if (Test-Path $gzPath) {
    Write-Host "data.gz exists: $((Get-Item $gzPath).Length) bytes"
} else {
    Write-Host "data.gz NOT FOUND"
}
EOF

